I1 = imread(fullpath(getIPCVpath() + "/images/lena.bmp"));
I2 = imread(fullpath(getIPCVpath() + "/images/lena7030.bmp"));
[S, TR, ROT, SC] = imphasecorr(I1, I2);
y = imfuse(I1, S, "colordiff");
imshow(y);

a = uint8([10 20; 30 40]);
b = uint8([40 30; 20 10]);
imshow(imfuse(a, b, "composite", 0.25));
